export interface FashionAnalysis {
  gender: 'male' | 'female' | 'uncertain';
  ageRange: string;
  bodyType: 'Slim' | 'Average' | 'Athletic' | 'Plus';
  facialFeatures: {
    shape: string;
    skinTone: string;
    hairColor: string;
  };
  confidence: number;
}

export interface Outfit {
  category: 'Casual' | 'Business' | 'Night';
  title: string;
  items: {
    top: string;
    bottom: string;
    shoes: string;
    accessories: string[];
  };
  colorPalette: string[];
  explanation: string;
}

export interface StyleRecommendations {
  analysis: FashionAnalysis;
  outfits: Outfit[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";
import { FashionAnalysis, StyleRecommendations, Outfit } from "../types";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeImageAndRecommend = async (base64Image: string): Promise<StyleRecommendations> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: "Analyze this image for fashion styling. Provide gender, age range, body type (Slim, Average, Athletic, Plus), face shape, skin tone, and hair color. Then provide 3 outfit recommendations for Casual, Business, and Night categories." }
      ]
    },
    config: {
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          analysis: {
            type: Type.OBJECT,
            properties: {
              gender: { type: Type.STRING },
              ageRange: { type: Type.STRING },
              bodyType: { type: Type.STRING },
              facialFeatures: {
                type: Type.OBJECT,
                properties: {
                  shape: { type: Type.STRING },
                  skinTone: { type: Type.STRING },
                  hairColor: { type: Type.STRING }
                }
              },
              confidence: { type: Type.NUMBER }
            }
          },
          outfits: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                category: { type: Type.STRING },
                title: { type: Type.STRING },
                items: {
                  type: Type.OBJECT,
                  properties: {
                    top: { type: Type.STRING },
                    bottom: { type: Type.STRING },
                    shoes: { type: Type.STRING },
                    accessories: { type: Type.ARRAY, items: { type: Type.STRING } }
                  }
                },
                colorPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
                explanation: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text || '{}') as StyleRecommendations;
};

export const chatWithStylist = async (message: string, history: any[]) => {
  const ai = getAIClient();
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: 'You are a world-class fashion stylist and image consultant. Help users with their fashion queries, offer tips on how to dress for their body type, and stay on top of current trends.'
    }
  });

  const result = await chat.sendMessage({ message });
  return result.text;
};

export const searchFashionTrends = async (query: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: query,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  return {
    text: response.text,
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => chunk.web) || []
  };
};

export const generateFashionVisual = async (prompt: string, aspectRatio: string = "1:1", size: string = "1K") => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [{ text: `High fashion editorial photography of: ${prompt}. Professional lighting, 8k resolution, cinematic composition.` }]
    },
    config: {
      imageConfig: {
        aspectRatio: aspectRatio as any,
        imageSize: size as any
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

export const editFashionImage = async (base64Image: string, editPrompt: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: editPrompt }
      ]
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

