import { analyzeImageAndRecommend, generateOutfitImage } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('analyze');
  const [analysisResult, setAnalysisResult] = useState<StyleRecommendations | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleImageUpload = async (base64: string) => {
    setIsLoading(true);
    try {
      // 1. Get Textual Analysis and Outfit Prompts
      const result = await analyzeImageAndRecommend(base64);
      setAnalysisResult(result);
      setActiveTab('outfits');

      // 2. Sequentially generate images for each outfit to enrich the UI
      if (result.outfits && result.outfits.length > 0) {
        for (let i = 0; i < result.outfits.length; i++) {
          const outfit = result.outfits[i];
          if (outfit.visualPrompt) {
            const imageUrl = await generateOutfitImage(outfit.visualPrompt);
            if (imageUrl) {
              setAnalysisResult(prev => {
                if (!prev) return null;
                const newOutfits = [...prev.outfits];
                newOutfits[i] = { ...newOutfits[i], imageUrl };
                return { ...prev, outfits: newOutfits };
              });
            }
          }
        }
      }
    } catch (err) {
      console.error("Analysis failed:", err);
      alert("Failed to analyze image. Please try again with a clearer photo.");
    } finally {
      setIsLoading(false);
